import React, { useState } from 'react';

const App = () => {
  const [mode, setMode] = useState('credit');
  const [balance, setBalance] = useState(0);
  const [history, setHistory] = useState([]);

  const handleModeToggle = () => {
    setMode(mode === 'credit' ? 'debit' : 'credit');
  };

  const handleDeposit = () => {
    setBalance(balance + 10);
    setHistory([...history, {
      type: 'deposit',
      amount: 10
    }]);
  };

  const handleWithdrawal = () => {
    setBalance(balance - 10);
    setHistory([...history, {
      type: 'withdrawal',
      amount: 10
    }]);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 w-96 rounded-md">
        <h2 className="text-[#C06C88] font-bold">AI Model Credit Tracker</h2>
        <button className="bg-[#411C56] text-white py-2 px-4 rounded-md" onClick={handleModeToggle}>{mode === 'credit' ? 'Debit' : 'Credit'}</button>
        <p className="text-[#C06C88] font-bold mt-2">Balance: $<span className="text-[#B7D7CD]">{balance}</span></p>
        <button className="bg-[#C06C88] text-white py-2 px-4 rounded-md" onClick={handleDeposit}>Deposit</button>
        <button className="bg-[#C06C88] text-white py-2 px-4 rounded-md" onClick={handleWithdrawal}>Withdraw</button>
        <ul className="mt-2 text-[#C06C88]">
          {history.map((transaction, index) => (
            <li key={index}>{transaction.type} by ${transaction.amount}</li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default App;
